// Constants
const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;
const PLAYER_SPEED = 5; // Units per second

// Variables
let canvas, ctx, playerPos = { x: 100, y: 300 };
let lastTime;

function init() {
    canvas = document.createElement('canvas');
    canvas.width = CANVAS_WIDTH;
    canvas.height = CANVAS_HEIGHT;
    ctx = canvas.getContext('2d');
    document.body.appendChild(canvas);
    window.addEventListener('keydown', handleKeyDown);
}

function startGame(time) {
    lastTime = time;
    setInterval(gameLoop, 16); // Roughly 60 FPS
}

function gameLoop(currentTime) {
    const deltaTime = currentTime - lastTime;
    update(deltaTime / 1000); // Convert to seconds
    draw();
    lastTime = currentTime;
}

function update(deltaTime) {
    // Player movement based on client-reported delta time
    playerPos.x += PLAYER_SPEED * deltaTime;
}

function draw() {
    ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    ctx.fillStyle = 'blue';
    ctx.fillRect(playerPos.x, playerPos.y, 20, 20);
}

function handleKeyDown(event) {
    switch (event.key) {
        case 'ArrowLeft':
            // Left movement logic
            break;
        case 'ArrowRight':
            // Right movement logic
            break;
    }
}

// Start the game
init();
startGame(performance.now());